@using sv_90ec9ff89dd445d08dc6a9f375d94c39.Services

<div class="profile-section">
    <h4>Profile Settings</h4>

    @if (_profile is null)
    {
        <p>Loading...</p>
        return;
    }

    @if (!string.IsNullOrEmpty(_message))
    {
        <div class="alert @(_isError ? "alert-danger" : "alert-success") alert-dismissible fade show" role="alert">
            @_message
            <button type="button" class="btn-close" @onclick="() => _message = null"></button>
        </div>
    }

    <div class="row">
        <div class="col-md-8">
            <div class="mb-3">
                <label class="form-label">Display Name</label>
                <input type="text" class="form-control" @bind="_displayName" />
            </div>

            <div class="mb-3">
                <label class="form-label">Email</label>
                <input type="email" class="form-control" @bind="_email" />
            </div>

            <div class="mb-3">
                <label class="form-label">Bio</label>
                <textarea class="form-control" rows="4" @bind="_bio"></textarea>
            </div>

            <div class="mb-3">
                <label class="form-label">Avatar URL</label>
                <input type="text" class="form-control" @bind="_avatarUrl" />
            </div>
        </div>

        <div class="col-md-4">
            <div class="avatar-preview">
                <label class="form-label">Avatar Preview</label>
                <div class="avatar-frame">
                    @if (!string.IsNullOrWhiteSpace(_avatarUrl))
                    {
                        <img src="@_avatarUrl" alt="Avatar" class="avatar-img" />
                    }
                    else
                    {
                        <div class="avatar-placeholder">No avatar</div>
                    }
                </div>
            </div>
        </div>
    </div>

    <div class="d-flex gap-2 mt-3">
        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
            @(_saving ? "Saving..." : "Save Changes")
        </button>
        <button class="btn btn-outline-secondary" @onclick="Discard" disabled="@_saving">
            Discard Changes
        </button>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public ISettingsService SettingsService { get; set; } = default!;

    private UserProfile? _profile;
    private string _displayName = "";
    private string _email = "";
    private string _bio = "";
    private string _avatarUrl = "";
    private string? _message;
    private bool _isError;
    private bool _saving;

    protected override async Task OnInitializedAsync()
    {
        _profile = await SettingsService.GetProfileAsync();
        PopulateFromProfile(_profile);
    }

    private void PopulateFromProfile(UserProfile profile)
    {
        _displayName = profile.DisplayName;
        _email = profile.Email;
        _bio = profile.Bio;
        _avatarUrl = profile.AvatarUrl;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _message = null;
        try
        {
            var updated = new UserProfile(_displayName, _email, _avatarUrl, _bio);
            await SettingsService.SaveProfileAsync(updated);
            _profile = updated;
            _message = "Profile saved successfully!";
            _isError = false;
        }
        catch (Exception ex)
        {
            _message = $"Failed to save profile: {ex.Message}";
            _isError = true;
        }
        finally
        {
            _saving = false;
        }
    }

    private void Discard()
    {
        if (_profile is not null)
        {
            PopulateFromProfile(_profile);
        }
        _message = null;
    }
}

.avatar-preview {
    text-align: center;
}

.avatar-frame {
    width: 150px;
    height: 150px;
    border-radius: 50%;
    overflow: hidden;
    margin: 0.5rem auto;
    border: 3px solid #dee2e6;
    display: flex;
    align-items: center;
    justify-content: center;
    background: #f8f9fa;
}

.avatar-img {
    width: 100%;
    height: 100%;
    object-fit: cover;
}

.avatar-placeholder {
    color: #adb5bd;
    font-size: 0.875rem;
}

@using sv_90ec9ff89dd445d08dc6a9f375d94c39.Services

<div class="notifications-section">
    <h4>Notification Preferences</h4>

    @if (_prefs is null)
    {
        <p>Loading...</p>
        return;
    }

    @if (!string.IsNullOrEmpty(_message))
    {
        <div class="alert alert-success alert-dismissible fade show" role="alert">
            @_message
            <button type="button" class="btn-close" @onclick="() => _message = null"></button>
        </div>
    }

    <div class="card mb-3">
        <div class="card-body">
            <h6 class="card-title">General</h6>

            <div class="form-check form-switch mb-2">
                <input class="form-check-input" type="checkbox" id="emailNotif" @bind="_emailNotifications" />
                <label class="form-check-label" for="emailNotif">Email Notifications</label>
            </div>

            <div class="form-check form-switch mb-2">
                <input class="form-check-input" type="checkbox" id="pushNotif" @bind="_pushNotifications" />
                <label class="form-check-label" for="pushNotif">Push Notifications</label>
            </div>

            <div class="form-check form-switch mb-2">
                <input class="form-check-input" type="checkbox" id="weeklyDigest" @bind="_weeklyDigest" />
                <label class="form-check-label" for="weeklyDigest">Weekly Digest</label>
            </div>
        </div>
    </div>

    <div class="card mb-3">
        <div class="card-body">
            <h6 class="card-title">Muted Channels</h6>
            <p class="text-muted small">Check channels you want to mute.</p>

            @foreach (var channel in _allChannels)
            {
                <div class="form-check mb-1">
                    <input class="form-check-input" type="checkbox" id="ch-@channel"
                           checked="@_mutedChannels.Contains(channel)"
                           @onchange="e => ToggleMute(channel, (bool)(e.Value ?? false))" />
                    <label class="form-check-label" for="ch-@channel">
                        #@channel
                    </label>
                </div>
            }
        </div>
    </div>

    <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
        @(_saving ? "Saving..." : "Save Preferences")
    </button>
</div>

@code {
    [Parameter, EditorRequired] public ISettingsService SettingsService { get; set; } = default!;

    private NotificationPrefs? _prefs;
    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private HashSet<string> _mutedChannels = [];
    private string? _message;
    private bool _saving;

    private static readonly List<string> _allChannels = ["general", "announcements", "engineering", "marketing", "support"];

    protected override async Task OnInitializedAsync()
    {
        _prefs = await SettingsService.GetNotificationPrefsAsync();
        _emailNotifications = _prefs.EmailNotifications;
        _pushNotifications = _prefs.PushNotifications;
        _weeklyDigest = _prefs.WeeklyDigest;
        _mutedChannels = [.._prefs.MutedChannels];
    }

    private void ToggleMute(string channel, bool muted)
    {
        if (muted)
            _mutedChannels.Add(channel);
        else
            _mutedChannels.Remove(channel);
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _message = null;
        try
        {
            var updated = new NotificationPrefs(_emailNotifications, _pushNotifications, _weeklyDigest, [.._mutedChannels]);
            await SettingsService.SaveNotificationPrefsAsync(updated);
            _prefs = updated;
            _message = "Preferences saved successfully!";
        }
        finally
        {
            _saving = false;
        }
    }
}

@using sv_90ec9ff89dd445d08dc6a9f375d94c39.Services

<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center"
         style="cursor: pointer;" @onclick="() => _expanded = !_expanded">
        <h6 class="mb-0">Change Password</h6>
        <span>@(_expanded ? "▲" : "▼")</span>
    </div>
    @if (_expanded)
    {
        <div class="card-body">
            @if (!string.IsNullOrEmpty(_message))
            {
                <div class="alert @(_isError ? "alert-danger" : "alert-success") alert-dismissible fade show" role="alert">
                    @_message
                    <button type="button" class="btn-close" @onclick="() => _message = null"></button>
                </div>
            }

            <div class="mb-3">
                <label class="form-label">Current Password</label>
                <input type="password" class="form-control" @bind="_currentPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">New Password</label>
                <input type="password" class="form-control" @bind="_newPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">Confirm New Password</label>
                <input type="password" class="form-control" @bind="_confirmPassword" />
            </div>
            <button class="btn btn-warning" @onclick="UpdatePasswordAsync" disabled="@_saving">
                @(_saving ? "Updating..." : "Update Password")
            </button>
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired] public ISettingsService SettingsService { get; set; } = default!;

    private bool _expanded;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private string? _message;
    private bool _isError;
    private bool _saving;

    private async Task UpdatePasswordAsync()
    {
        _message = null;

        if (string.IsNullOrWhiteSpace(_currentPassword) || string.IsNullOrWhiteSpace(_newPassword))
        {
            _message = "Please fill in all password fields.";
            _isError = true;
            return;
        }

        if (_newPassword != _confirmPassword)
        {
            _message = "New password and confirmation do not match.";
            _isError = true;
            return;
        }

        _saving = true;
        try
        {
            await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
            _message = "Password updated successfully!";
            _isError = false;
            _currentPassword = "";
            _newPassword = "";
            _confirmPassword = "";
        }
        catch (Exception ex)
        {
            _message = $"Failed to update password: {ex.Message}";
            _isError = true;
        }
        finally
        {
            _saving = false;
        }
    }
}

@using sv_90ec9ff89dd445d08dc6a9f375d94c39.Services

@if (_sessionToRevoke is not null)
{
    <div class="modal-backdrop fade show"></div>
    <div class="modal fade show d-block" tabindex="-1" role="dialog">
        <div class="modal-dialog modal-dialog-centered" role="document">
            <div class="modal-content">
                <div class="modal-header">
                    <h5 class="modal-title">Revoke Session</h5>
                    <button type="button" class="btn-close" @onclick="Cancel"></button>
                </div>
                <div class="modal-body">
                    <p>Are you sure you want to revoke the session on <strong>@_sessionToRevoke.Device</strong> from <strong>@_sessionToRevoke.Location</strong>?</p>
                    <p class="text-muted small">This will sign out that device immediately.</p>
                </div>
                <div class="modal-footer">
                    <button class="btn btn-secondary" @onclick="Cancel" disabled="@_revoking">Cancel</button>
                    <button class="btn btn-danger" @onclick="ConfirmAsync" disabled="@_revoking">
                        @(_revoking ? "Revoking..." : "Revoke Session")
                    </button>
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter] public ActiveSession? Session { get; set; }
    [Parameter] public EventCallback OnConfirmed { get; set; }
    [Parameter] public EventCallback OnCancelled { get; set; }

    private ActiveSession? _sessionToRevoke;
    private bool _revoking;

    protected override void OnParametersSet()
    {
        _sessionToRevoke = Session;
    }

    private async Task ConfirmAsync()
    {
        _revoking = true;
        try
        {
            await OnConfirmed.InvokeAsync();
        }
        finally
        {
            _revoking = false;
        }
    }

    private async Task Cancel()
    {
        await OnCancelled.InvokeAsync();
    }
}

