@using sv_90ec9ff89dd445d08dc6a9f375d94c39.Services

<div class="card mb-3">
    <div class="card-body">
        <h6 class="card-title">Active Sessions</h6>
        <div class="table-responsive">
            <table class="table table-sm table-hover mb-0">
                <thead>
                    <tr>
                        <th>Device</th>
                        <th>Location</th>
                        <th>Last Active</th>
                        <th></th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var session in Sessions)
                    {
                        <tr>
                            <td>@session.Device</td>
                            <td>@session.Location</td>
                            <td>@FormatLastActive(session.LastActive)</td>
                            <td>
                                @if (session.Id != CurrentSessionId)
                                {
                                    <button class="btn btn-outline-danger btn-sm"
                                            @onclick="() => OnRevokeRequested.InvokeAsync(session)">
                                        Revoke
                                    </button>
                                }
                                else
                                {
                                    <span class="badge bg-success">Current</span>
                                }
                            </td>
                        </tr>
                    }
                </tbody>
            </table>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public List<ActiveSession> Sessions { get; set; } = [];
    [Parameter] public string CurrentSessionId { get; set; } = "sess-1";
    [Parameter] public EventCallback<ActiveSession> OnRevokeRequested { get; set; }

    private static string FormatLastActive(DateTime lastActive)
    {
        var diff = DateTime.UtcNow - lastActive;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }
}

@using sv_90ec9ff89dd445d08dc6a9f375d94c39.Services

<div class="security-section">
    <h4>Security Settings</h4>

    @if (_settings is null)
    {
        <p>Loading...</p>
        return;
    }

    @if (!string.IsNullOrEmpty(_message))
    {
        <div class="alert alert-success alert-dismissible fade show" role="alert">
            @_message
            <button type="button" class="btn-close" @onclick="() => _message = null"></button>
        </div>
    }

    <ChangePasswordPanel SettingsService="SettingsService" />

    <div class="card mb-3">
        <div class="card-body d-flex justify-content-between align-items-center">
            <div>
                <h6 class="mb-1">Two-Factor Authentication</h6>
                <span class="badge @(_twoFactorEnabled ? "bg-success" : "bg-secondary")">
                    @(_twoFactorEnabled ? "Enabled" : "Disabled")
                </span>
                @if (_settings.LastPasswordChange.HasValue)
                {
                    <p class="text-muted small mt-2 mb-0">
                        Last password change: @_settings.LastPasswordChange.Value.ToString("MMM dd, yyyy")
                    </p>
                }
            </div>
            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox" id="twoFactor" @bind="_twoFactorEnabled" />
            </div>
        </div>
    </div>

    <ActiveSessionsTable Sessions="_settings.Sessions.ToList()"
                         OnRevokeRequested="RequestRevoke" />

    <RevokeSessionDialog Session="_sessionToRevoke"
                         OnConfirmed="ConfirmRevokeAsync"
                         OnCancelled="CancelRevoke" />
</div>

@code {
    [Parameter, EditorRequired] public ISettingsService SettingsService { get; set; } = default!;

    private SecuritySettings? _settings;
    private bool _twoFactorEnabled;
    private ActiveSession? _sessionToRevoke;
    private string? _message;

    protected override async Task OnInitializedAsync()
    {
        _settings = await SettingsService.GetSecuritySettingsAsync();
        _twoFactorEnabled = _settings.TwoFactorEnabled;
    }

    private void RequestRevoke(ActiveSession session)
    {
        _sessionToRevoke = session;
    }

    private async Task ConfirmRevokeAsync()
    {
        if (_sessionToRevoke is null) return;

        await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
        _message = $"Session on {_sessionToRevoke.Device} has been revoked.";
        _sessionToRevoke = null;
        _settings = await SettingsService.GetSecuritySettingsAsync();
    }

    private void CancelRevoke()
    {
        _sessionToRevoke = null;
    }
}

