.preview-body {
    border-radius: 0.5rem;
    padding: 1.25rem;
    transition: all 0.2s ease;
}

/* Theme variants */
.preview-light {
    background: #ffffff;
    color: #212529;
    border: 1px solid #dee2e6;
}

.preview-dark {
    background: #1e1e2e;
    color: #cdd6f4;
    border: 1px solid #45475a;
}

.preview-system {
    background: #f0f0f5;
    color: #333;
    border: 1px solid #c0c0c0;
}

/* Font sizes */
.font-small { font-size: 0.8rem; }
.font-medium { font-size: 1rem; }
.font-large { font-size: 1.15rem; }

/* Compact mode */
.compact { padding: 0.5rem 1rem; line-height: 1.3; }
.compact .preview-card { padding: 0.5rem; margin-top: 0.5rem; }

/* Preview elements */
.preview-text { margin-bottom: 0.75rem; opacity: 0.85; }

