@page "/settings"
@using sv_90ec9ff89dd445d08dc6a9f375d94c39.Services
@inject ISettingsService SettingsService
@rendermode InteractiveServer

<PageTitle>Settings</PageTitle>

<div class="settings-dashboard">
    <div class="settings-nav">
        <SettingsSidebar ActiveSection="@_activeSection"
                         OnSectionSelected="section => _activeSection = section" />
    </div>

    <div class="settings-content">
        @switch (_activeSection)
        {
            case "profile":
                <ProfileSection SettingsService="SettingsService" />
                break;
            case "notifications":
                <NotificationsSection SettingsService="SettingsService" />
                break;
            case "security":
                <SecuritySection SettingsService="SettingsService" />
                break;
            case "appearance":
                <AppearanceSection SettingsService="SettingsService" />
                break;
        }
    </div>
</div>

@code {
    private string _activeSection = "profile";
}

